import React, { useEffect, useState } from 'react';
import { Button, View } from 'react-native';
import { authorize, refresh, AuthConfiguration, TokenResponse } from 'react-native-app-auth';

const config: AuthConfiguration = {
  clientId: 'your_client_id',
  clientSecret: 'your_client_secret',
  redirectUrl: 'your_redirect_url',
  scopes: ['your_scopes'],
  serviceConfiguration: {
    authorizationEndpoint: 'your_authorization_endpoint',
    tokenEndpoint: 'your_token_endpoint',
  },
};

const App = () => {
  const [authState, setAuthState] = useState(null);

  const handleAuthorize = async () => {
    try {
      const result = await authorize(config);
      setAuthState(result);
    } catch (error) {
      console.log(error);
    }
  };

  const handleRefresh = async () => {
    if (!authState) {
      return;
    }

    const { refreshToken } = authState;

    try {
      const result = await refresh(config, {
        refreshToken,
      });

      setAuthState(result);
    } catch (error) {
      console.log(error);
    }
  };

  useEffect(() => {
    if (authState) {
      const intervalId = setInterval(handleRefresh, 1000 * 60 * 60); // Refresh every hour
      return () => clearInterval(intervalId);
    }
  }, [authState]);

  return (
    <View>
      <Button onPress={handleAuthorize} title="Authorize" />
    </View>
  );
};

export default App;